import type { CommandController } from './index';

export async function startRebaseOperation(this: CommandController, run: () => Promise<void>): Promise<void> {
  try {
        await run();
      } catch (error) {
        const issue = this.classifyRebaseIssue(error);
        if (issue.kind === 'conflict') {
          await this.handleOperationConflict('rebase', this.state.refreshAll());
          return;
        }
        throw error;
      }
  
      await this.state.refreshAll();
      await this.showRebaseProgressFeedback();
}
